INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务：帮忙办理入住的Viria还有退房时遇到的小雨服务态度非常好 特别热情 效率', '服务：帮忙办理入住的Viria还有退房时遇到的小雨服务态度非常好 特别热情 效率也很高 服务真的非常专业 我入住的很满意。酒店房间也很不错 很干净卫生 采光也很好 非常推荐～', '2023-08-02', 5, '[''前台服务'', ''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235y12000bt9ns0gE625_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '住的很满意，酒店环境不错，Mikey等每一位工作人员都很热情专业～ 餐食水准一流', '住的很满意，酒店环境不错，Mikey等每一位工作人员都很热情专业～ 餐食水准一流！', '2023-03-14', 5, '[''整体满意度'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230j12000arttmlr7E92_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店确实很漂亮，花园还有瀑布，4楼还有博物馆，在酒店还能玩一天，管家Viri', '花园酒店确实很漂亮，花园还有瀑布，4楼还有博物馆，在酒店还能玩一天，管家Viria特别贴心，一次非常好的体验', '2023-05-03', 5, '[''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236x12000b564q9x6DE5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '三十年前设计建造的酒店到今天仍然令人兴奋，说明长远规划很重要，修新如新的样式尤其', '三十年前设计建造的酒店到今天仍然令人兴奋，说明长远规划很重要，修新如新的样式尤其是大堂不变的中国风更让人豁然开朗心旷神怡，卫生整治、布局合理、花园、瀑布是网红亮点，三楼的桃园馆尽管收费不菲，但也食有所值！还会再来，感谢前台的托尼先生為我升級了视线开阔的房间。', '2023-06-19', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232h2224vhdtct1c09B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s2224vhdtd0r411BF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s2215fe0nahb445B5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '为了看校长在佛山的演唱会，提前在广州选择入住花园酒店，前台美女Viria服务特别', '为了看校长在佛山的演唱会，提前在广州选择入住花园酒店，前台美女Viria服务特别棒，细心的介绍酒店的设施分布，贴心的送了两天的早餐，让我们机会把几个特色餐厅都尝试一下。特别推荐桃园馆，味道真的不错！入住满意，推荐！', '2023-09-11', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234r12000c3vo3y06437_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000c3vpleqA870_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000c3vohzo0051_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000c3vihyb201F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236712000c3vsmp11FD7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000c3vtwi66862_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236d12000c3vke55A47B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000c3vnzu5B2AE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这个酒店十分值得推荐，周边交通便利，酒店后花园环境优美，舒适宜居。穿粉红色衣服的', '这个酒店十分值得推荐，周边交通便利，酒店后花园环境优美，舒适宜居。穿粉红色衣服的小姐姐Jane服务很好??。下次还来[胜利]', '2023-02-15', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000aockzn9FC8C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000aocl9zo3FB4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '中国最早的一批五星级酒店，老外居多，厚重的年代感，不过保养非常好，管理和服务非常', '中国最早的一批五星级酒店，老外居多，厚重的年代感，不过保养非常好，管理和服务非常到位，特别是所住楼层的管家小朱，始终微笑相迎。酒店内的美食也非多，值得体验。', '2024-03-18', 4, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235k12000dfx3gfb514F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000dfy43uu4F6C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店被鲜花绿树环抱，与酒店名字吻合。大堂富丽堂皇，装饰新颖别致，摆满了精致鲜花，', '酒店被鲜花绿树环抱，与酒店名字吻合。大堂富丽堂皇，装饰新颖别致，摆满了精致鲜花，好温馨！前台JUSTIN微笑服务，业务熟练，办理入住手续快，安排房间满意。房间设施齐全，温暖、舒适、卫生无死角，感谢JACK的优质服务。酒店很多餐厅，二楼餐厅广州美食品种丰富，不仅好吃，且服务好。早餐环境好，一边品美食，一边赏瀑布，一边喝咖啡，很享受。酒店后面是一个大花园，有瀑布，有小桥，有流水，也有游来游去的金鱼，鲜花遍地盛开，非常美！四层博物馆值得浏览，记录着酒店的发展历程，很不错！游池、桑拿、健身环境舒适，可以体验。在大堂碰到郑璟，认真听取客人的入住体验，友善解答客人问题，美赞！出行的快乐就是选对了一家好酒店！花园酒店让广州之旅不虚此行！', '2024-01-03', 5, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234w224x8tonikit5930_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i224x8tonig1gAA9A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02307224x8tonikivBDCC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02328224x8tonvd3yA2D5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234w224x8toniheu8A11_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02305224x8tonikz30BCA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234o224x8tonig1lE95D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v224x8tonzduv5F7E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '小钟和小花对客人热情周到，服务很好！早餐非常好吃，很丰富，酒店环境不错，卫生干净', '小钟和小花对客人热情周到，服务很好！早餐非常好吃，很丰富，酒店环境不错，卫生干净，住得非常舒服，下次还会再选择。', '2023-03-03', 5, '[''整体满意度'', ''餐饮设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231y12000aqfe4w63507_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000aqfdknk2CC5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000aqfcqraF7B2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位于市中心，贝聿铭大师设计的酒店，极具岭南风格，商务旅游都方便。服务非常有特色，', '位于市中心，贝聿铭大师设计的酒店，极具岭南风格，商务旅游都方便。服务非常有特色，入住办理非常迅速，服务态度很好，入住遇到一些小问题，前台梁婉彤耐心地给我们解决，反映出老牌粤式风格的高水准。红棉大床房的中式风格圆桌很很喜欢。房间卫生干净。酒店及周边吃饭购物方便。', '2023-02-12', 5, '[''前台服务'', ''周边配套'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0236i12000anma1wf1D62_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000anmqaa7CD36_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000anmdhnaFF9A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000anmhgm56286_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234e12000anmwriqBF3B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000anmfdxc0ADD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000ann1zmzE852_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000anmzxet6C64_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '事隔半年,再到广州游玩仍是选择入住花园酒店,体验还是那么好. 非常感谢登记入住的', '事隔半年,再到广州游玩仍是选择入住花园酒店,体验还是那么好. 非常感谢登记入住的kasas,因为我们临时决定订住多两晚，给到我们最佳订住方案，我们带着两岁多的小孩，给我们赠送了早餐也升级了房间，小孩在瀑布餐厅就餐很开心??.也感谢大堂liven,我们在大堂等候出租车时，好几次主动协助我们，女儿还主率她手，让我们腾出空间处理其他事情，非常感谢????,大堂lulu在我们退房时给小孩送了一只毛公仔作记念，小孩高兴的抱着回家. 两次入住，我们夫妻俩都十分满意，下次来广州仍会选择入住花园酒店
在此高度表扬Kasas，年纪轻轻，处事大方稳重，态度亲善，安排贴心，希望酒店能够重点栽培这个??可造之才。', '2025-04-12', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/02364224x90kun0032ACC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02327224x90kwvn4hDBE8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02301224x90kuag180152_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02342224x90kuqx8l0ACB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我最近有幸入住了广州的岭南花园酒店，这真是一次非凡的体验。从我们到达的那一刻起，', '我最近有幸入住了广州的岭南花园酒店，这真是一次非凡的体验。从我们到达的那一刻起，服务、款待和整体氛围都非常出色。工作人员非常有礼貌、细心，总是愿意提供帮助，让我们的住宿非常顺利和方便。

特别感谢 Winnie Lie，她竭尽全力确保我们的入住过程顺利而快速。她的专业精神和热情态度确实为我们整个住宿奠定了基调。

酒店的食物同样令人印象深刻——各种美味佳肴，精美呈现，始终新鲜。

总的来说，我在岭南花园酒店度过了一段美好的时光，一定会再次入住。强烈推荐给所有来广州的人！', '2025-04-07', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230p12000jmh3drdA3D8_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230u12000jmh3kqgBAC5_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我刚刚在广州花园酒店住了两晚，这超出了我的预期。工作人员非常热情周到，确保满足我', '我刚刚在广州花园酒店住了两晚，这超出了我的预期。工作人员非常热情周到，确保满足我们的所有需求。我们的房间宽敞舒适，可欣赏到迷人的城市景观。酒店的餐饮是一大亮点，提供各种美味佳肴。酒店位置优越，方便客人游览附近的景点。强烈推荐！', '2025-04-06', 5, '[''整体满意度'', ''前台服务'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0236j324x90dx5fdyE901_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u324x90dym2qbDAD2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店位置极佳，交通很方便，隣近淘金地鉄站。酒店宏伟奢华的装修，令我叹为观止，', '花园酒店位置极佳，交通很方便，隣近淘金地鉄站。酒店宏伟奢华的装修，令我叹为观止，所有服务人员都很专业，尤其是前台小钟热情招待，还升级我们到套房房间，虽然等多两小时才入住也值得，其间还分配一间普通房间先休息，另我及家人感觉很舒服。下次到广州一定再入住花园酒店。??????', '2025-04-02', 5, '[''交通便利性'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232y224x90bs4m2pC93D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f224x90bsjeyd2C55_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v224x90buqji6CA91_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e224x90busi7b4572_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236a224x90bstb0h7196_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k224x90bv45vbB056_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x224x90brra05818F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '相隔了一年多再次入住花园酒店，和之前感觉一样，配得上我广州最喜欢酒店，对比众多五', '相隔了一年多再次入住花园酒店，和之前感觉一样，配得上我广州最喜欢酒店，对比众多五星级酒店所在的天河，琶洲，花园相对我而言交通更其方便，离南站45分钟，机场1小时左右，办理入住仍然高效，前后不到三分钟，每次都能为我升级我以前经常住的房型，这点就是我每次到广州首选花园原因，自助晚餐性格比高补充食物及时，房间布局舒适大气，用品齐全卫生，广州能令我房间最满意的也是花园，服务也充满人性化，而且还相当高效，每次来住都感觉花园也在不断进步。总之只能给予101分…', '2025-03-16', 5, '[''整体满意度'', ''交通便利性'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0230v224x8zy30z5bB3B0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z224x8zy1o2m95971_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n224x8zy31k2z996B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r224x8zy2ge6h79CE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i224x8zy29ijeB09C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02311224x8zy2lw4s488E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我想花点时间表达我对我和家人最近在岭南花园酒店住宿期间的美好体验的真诚感谢。这是', '我想花点时间表达我对我和家人最近在岭南花园酒店住宿期间的美好体验的真诚感谢。这是我们第三次入住贵酒店，我们再次被深深地打动。

我住过许多四星级和五星级酒店。很难找到一家既符合我所有卓越标准又能让我家人负担得起的酒店。然而，岭南花园酒店超出了我的所有期望。

郁郁葱葱的花园环境，还有瀑布和鱼塘等宁静的水景，提供了与众不同的感官休憩之所。房间一尘不染，员工服务专业、友好、尊重，整体氛围无疑是家庭友好的。

此外，屋顶游泳池为儿童和成人提供了一个放松和享受的绝佳环境。酒店的中心位置为我们的住宿增添了便利，我必须特别提到美味的自助晚餐——我衷心向所有寻求难忘和愉快酒店体验的人推荐岭南花园酒店。再次感谢您的热情款待。我们期待再次光临。', '2025-03-15', 5, '[''整体满意度'', ''公共设施'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/02364224x8zx7xkz31DE6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02364224x8zx710xr6126_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x224x8zx81sp6396C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w224x8zx6pkauB691_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02355224x8zx6q93v6A67_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02352224x8zx7pbre2071_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我最近入住了广州的岭南花园酒店，这真是一次愉快的体验。从我到达的那一刻起，酒店工', '我最近入住了广州的岭南花园酒店，这真是一次愉快的体验。从我到达的那一刻起，酒店工作人员就热情周到，确保入住过程顺利进行。酒店设计精美，融合了现代奢华与传统风格。大堂宏伟壮观，氛围宁静，为接下来的住宿奠定了基调。', '2025-03-16', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232r12000j4b8g844158_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0236012000j4b6s0l14BC_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230l12000j4b9gwuF95B_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这家酒店一直是我在广州的首选。员工乐于助人，态度友好。中餐厅的食物总体不错，酒店', '这家酒店一直是我在广州的首选。员工乐于助人，态度友好。中餐厅的食物总体不错，酒店客人可享受 25% 的折扣。请务必告诉他们您的房间号。附近有不错的餐厅和购物中心，交通便利。地铁站就在酒店旁边，适合喜欢乘坐地铁的人。

但是，酒店后面正在施工。尽管关闭了双层玻璃窗，客房仍能听到噪音。我很感谢接待员在办理入住手续时提醒我，并尽力让我远离施工现场。所以如果你对噪音敏感，请当心。施工时间为上午 8 点至晚上 10 点！', '2025-03-02', 5, '[''安静程度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235t224x8znrx6v88F4C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02353224x8znrr3gb6F20_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x224x8znrwb925BD4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h224x8znrs6pcE343_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e224x8znqyiyt0628_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务、设施可以，早餐食物很一般，咖啡难饮（因??咖啡机坏坏地，另一部全坏，不', '酒店服务、设施可以，早餐食物很一般，咖啡难饮（因??咖啡机坏坏地，另一部全坏，不能使用，晚上楼下地盆噪音很严重，全晚影响睡眠。', '2025-04-10', 3, '[''餐饮设施'', ''房间设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236x224x90j156xb5A77_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '在花园酒店住得很棒！一如既往。五星级的设施和服务。热水浴缸非常适合在户外放松和游', '在花园酒店住得很棒！一如既往。五星级的设施和服务。热水浴缸非常适合在户外放松和游泳。这是我们度假的首选之地。', '2025-04-07', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236x12000jm5nlpw6102_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000jm5s9p13C1F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '地点在淘金地铁站上，方便自由行去北京路。对面广州友谊商店东西偏贵，款式亦不最新颕', '地点在淘金地铁站上，方便自由行去北京路。对面广州友谊商店东西偏贵，款式亦不最新颕的。酒点内的博物馆值得一看。', '2025-03-29', 4, '[''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0235e12000jeoi4388B30_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230s12000jeolpxb9A13_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231z12000jeojbitD52E_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233u12000jeoiprw855D_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234s12000jeohsrcB1C9_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为广州老牌酒店，整个服务和地理位子都非常好，酒店门口就是地铁站，出入方便。入住', '作为广州老牌酒店，整个服务和地理位子都非常好，酒店门口就是地铁站，出入方便。入住时酒店将房间升级，本是为了浸浴才订这间酒，但发现浴缸一直漏水，所以最后都没有浸到，感觉很失望。', '2025-01-25', 4, '[''房间设施'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233i224x8yvqyxrhC44B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02336224x8yvrlq7u3D8B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '套餐很超值，包括了2人早餐和夜茶，夜茶原来是2小时任吃，酒店很有气派，也算维护得', '套餐很超值，包括了2人早餐和夜茶，夜茶原来是2小时任吃，酒店很有气派，也算维护得很好了，不过食物真的强差人意，夜茶点心种类不少，但套餐里没写清楚是任吃，我们是吃了晚餐再去，最晚21点要到，22点关门，食物完全没有惊喜，还不如其他酒楼，好处是份量少可以多试几种。早餐是清真餐厅都没有猪肉的，但也是不合我的口味，连即磨咖啡也不行，虽然瀑布就在餐厅旁，但玻璃脏不太生得见，来一次见识过就可以。', '2025-01-04', 4, '[''餐饮设施'', ''性价比'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233112000hl0um516886_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000hl06zgd01B0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000hl00ptd8E9B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我最近在花园酒店的住宿非常满意！虽然刚到达酒店时房间还没有准备好，但酒店的前台工', '我最近在花园酒店的住宿非常满意！虽然刚到达酒店时房间还没有准备好，但酒店的前台工作人员Winnie Wei非常友善，主动为我升级了房间，让我感到非常惊喜和感激。房间干净舒适，设施完善，服务也相当周到。强烈推荐这家酒店，期待下次再来！', '2024-12-29', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232b224x8yauaf5h3152_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i224x8yaw7ks6DD81_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o224x8yatrzygCD11_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i224x8yauaf5g2E5C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这家酒店的卫生超级棒的!好喜欢在瀑布餐厅吃饭，', '这家酒店的卫生超级棒的!好喜欢在瀑布餐厅吃饭，
在这里用餐是一种享受，瀑布的声音让人心旷神怡！', '2025-03-22', 5, '[''餐饮设施'', ''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236g224x902xabaa961A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w224x902v00tbAF97_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u224x902v8ys1AD9B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a224x902vi7gl3364_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '趁着圣诞假期，跟家人到广州和珠海玩了五日四夜。25日早上到了广州，便马上到花园酒', '趁着圣诞假期，跟家人到广州和珠海玩了五日四夜。25日早上到了广州，便马上到花园酒店放下行李。酒店大堂有一颗很大的圣诞树，绝对是旅客的打卡点。踏入酒店，酒店的员工和前台都非常有礼貌，热情地款待客人。由于时间尚早，房间尚未收拾好，我们把行李存放在礼宾部，便去对面的商场饮早茶。游览完上下九步行街和沙面之后，我们便回到酒店，拿了房卡，便到房间里稍作休息。

由于我们是出发前几天才决定入住花园酒店的，订房的时候没有很仔细地查看， 打开房间的一刻，惊喜地发现房间带客厅的，非常宽敞。我们渡过了一个舒适的晚上。

我们买的住宿券是包早餐和晚上任点任食点心的。所以，稍作休息之后我们便到荔湾享用夜茶。本来我们是预约七点半的，但是都要等候好一会儿才能进去。虽然款式种类不算很多，而味道也只是不过不失，上菜速度都算几快，我们都吃得很饱才离开。

第二天早上在地下的瀑布餐厅享用早餐。也许因为是圣诞节假期外国客人比较多的缘故，我们来到餐厅就发现有很多人排队，等了好一会儿，才安排到四人枱让我们入去享用早餐。早餐的食物选择算是比较多。我们坐的位置就在瀑布前的区域，我们以瀑布作为背景打卡之后，便开始大快朵颐了。

酒店外面就是地铁淘金站的入口，如果不打车，乘搭地铁也是十分方便的。

整体上这次的入住体验十分舒适愉快。', '2024-12-30', 4, '[''整体满意度'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233h224x8ybmts5h8373_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e224x8ybpafotF5DA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l224x8ybomckwCC76_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我们入住的那天是圣诞节，那天人很多，但酒店服务还不错。房间干净，看起来很新，很不', '我们入住的那天是圣诞节，那天人很多，但酒店服务还不错。房间干净，看起来很新，很不错。早餐不是五星级的，大部分食物味道清淡又冷。不过，他们确实提供了下午茶和欢乐时光自助餐，很不错，很愉快。', '2024-12-28', 4, '[''餐饮设施'', ''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234z224x8ya94gyrAEF6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m224x8ya7aaqr2CE2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h224x8ya7t7492981_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234e224x8ya8vwyk0E6B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02341224x8yaa1s4k220E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常好，舒适，非常漂亮，交通便利，著名地标，服务很棒', '非常好，舒适，非常漂亮，交通便利，著名地标，服务很棒', '2025-04-17', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/02306224x90omyab47563_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '交通方便，房间舒适，服务优良，地理位置优越，自助早餐丰富，到广州必住酒店推介', '交通方便，房间舒适，服务优良，地理位置优越，自助早餐丰富，到广州必住酒店推介', '2025-03-16', 5, '[''交通便利性'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234p224x8zxxadtd8D69_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i224x8zxxbg3uCBE8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r224x8zxyb3tjB6D7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z224x8zxwrdd83A7A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f224x8zxwdz50CBBF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v224x8zxwxqc0FABB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f224x8zxx3vbc8EB9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02345224x8zxwvulxA2CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02304224x8zxx46h2BF70_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我次次去广州都住呢间酒店 除咗方便之外 服务亦好好 服务员都好靓', '我次次去广州都住呢间酒店 除咗方便之外 服务亦好好 服务员都好靓', '2025-03-03', 4, '[''交通便利性'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233d224x8znyk8ma78F6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '用住宿券换了两个房间，前台安排到公寓式大套间，内有4套房2大厅，2佰多3佰平方，', '用住宿券换了两个房间，前台安排到公寓式大套间，内有4套房2大厅，2佰多3佰平方，地方好大，唯公寓式装修是8O，90年代，还包含了夜茶及翌日早餐，酒店位置十分方便在越秀区淘金站，前方有友谊商店及丽柏广场饮食购物，走5分钟有保利时光里大型购物中心等', '2024-11-14', 3, '[''周边配套'', ''交通便利性'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0236i224x8xib5a1y6991_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02313224x8xia377hF434_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n224x8xiar7sjC991_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p224x8xi9thy253E6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230l224x8xia377i0536_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c224x8xicev5y3537_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '舒适，服务态度好', '舒适，服务态度好', '2025-04-14', 4, '